async (params, browser) => {
  // Open Gmail
  await browser.open('https://mail.google.com/mail/u/0/#inbox')

  // Wait for Gmail to load
  await browser.waitForSelector('input[aria-label=\'Search mail\']', 15000)

  // Let Gmail fully initialize
  await browser.wait(2000)

  // Search for the email by subject
  const search_email = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search mail"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.select(); document.execCommand('insertText', false, \`subject:' + params.subject + '\`); await new Promise(r => setTimeout(r, 300)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Select the matching email checkbox
  const select_email = await browser.evaluate(`const rows = document.querySelectorAll('tr.zA'); if (rows.length === 0) return { error: 'No emails found matching the subject' }; const target = params.subject.toLowerCase(); let bestMatch = rows[0]; for (const row of rows) { const subjectEl = row.querySelector('.bog span, .y6 span'); if (subjectEl && subjectEl.textContent.trim().toLowerCase().includes(target)) { bestMatch = row; break; } } const checkbox = bestMatch.querySelector('.oZ-jc [role="checkbox"], .xY .oZ-jc'); if (checkbox) { checkbox.click(); } else { const checkArea = bestMatch.querySelector('.oZ-jc'); if (checkArea) checkArea.click(); } return { selected: true }`)

  // Wait for selection to register
  await browser.wait(1000)

  // Click labels button
  const open_label_menu = await browser.evaluate(`const labelBtn = document.querySelector('[aria-label="Labels"]') || document.querySelector('.ar9 + .ar9 + .ar9') || document.querySelector('[act="28"]'); if (labelBtn) { labelBtn.click(); } else { throw new Error('Labels button not found'); } return { label_menu_opened: true }`)

  // Wait for label menu to open
  await browser.wait(1500)

  // Type label name in search
  const type_label = await browser.evaluate(`const labelSearch = document.querySelector('.aX3 input, .J-M-JJ input, input[type="text"][aria-label*="label" i]') || document.querySelector('.J-M .J-M-JJ input'); if (labelSearch) { labelSearch.focus(); await new Promise(r => setTimeout(r, 300)); document.execCommand('insertText', false, params.label); labelSearch.dispatchEvent(new Event('input', { bubbles: true })); await new Promise(r => setTimeout(r, 1000)); } return { label_typed: true }`)

  // Wait for label to appear
  await browser.wait(1000)

  // Select label and apply
  const result = await browser.evaluate(`const labelItems = document.querySelectorAll('.J-N, .J-Kh, [role="menuitemcheckbox"]'); const target = params.label.toLowerCase(); let found = false; for (const item of labelItems) { const text = item.textContent.trim().toLowerCase(); if (text.includes(target)) { item.click(); found = true; break; } } if (!found && labelItems.length > 0) { labelItems[0].click(); found = true; } await new Promise(r => setTimeout(r, 500)); const applyBtn = document.querySelector('.J-at1-auR, .J-at1-auR .J-at1-atl') || document.querySelector('button[name="ok"]'); if (applyBtn) { applyBtn.click(); } return { success: found, message: found ? 'Label applied' : 'Label not found', label: params.label, subject: params.subject }`)

  // Wait for label to be applied
  await browser.wait(1500)

  return result
}
